var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SORIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"목적지 도착. 지근거리 안에 포착되는 적 없음. 안전확보완료.","JPN":"目的地到着。至近距離内に捕捉される敵なし。安全確保完了。","ENG":"We have reached the destination. No enemies in sight. Area secured.","TWN":"到達目的地。近距離內沒有發現敵人。確保安全，完畢。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_NPC_FOOLSDAY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","text":{"KOREA":"여긴 옥상이잖아?","JPN":"ここは屋上じゃない？","ENG":"Isn't this the company's rooftop?","TWN":"這裡不是屋頂嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"맞아요. 여긴 금연구역이 되고 직원들의 발길이 뜸해졌으니 안심하셔도 돼요.","JPN":"はい、ここが禁煙区域になってから社員たちもあまり来なくなったので、安心してください。","ENG":"That's right. Don't worry. People stopped coming up here once it was designated a no-smoking area.","TWN":"沒錯。這裡是禁菸區，上來這裡的員工也變少了，大家可以放心。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","text":{"KOREA":"네가 날 도와준 거야?","JPN":"あなたが私を助けてくれたの？","ENG":"Were you the one who helped me?","TWN":"是你幫我的嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"전 계획만 세웠을 뿐이에요.","JPN":"僕は計画を立てただけです。","ENG":"I only devised the plan.","TWN":"我只是做做計畫而已。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"계획을 실행에 옮길 수 있었던 건 소림이의 뛰어난 스텔스 능력 덕분이죠.","JPN":"計画を実行できたのはミズキちゃんの優れたステルス能力のおかげです。","ENG":"We couldn't have implemented the plan without Sorim's outstanding stealth abilities.","TWN":"能夠將計劃實際且正確的實施，多虧了蕭林出色的隱身能力。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":" ……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"솔직히 도움을 받을 줄은 몰랐어. 여기 직원들은 전부 사장 말만 따르는 줄 알았거든.","JPN":"正直助けられると思わなかった。ここの社員はみんな社長の指示どおりに動くと思ってたから。","ENG":"Honestly, I didn't expect anyone to help me. I thought all the employees just obeyed the President.","TWN":"說實話，我沒想到會得到幫助。 我以爲這裡的工作人員都只聽老闆的話呢。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":" ……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"직접 보셨다면 알겠지만, 대표님은 지금 몹시 불안정한 상태예요.","JPN":"さっき会ったのでわかると思いますが、社長は今とても不安定な状態なんです。","ENG":"As you may have noticed, the Boss is extremely unstable right now.","TWN":"親眼看到的話就會知道，代表他現在處於非常不穩定的狀態。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"정상은 아니지. 날 회사에 숨어든 스파이라면서 누명을 씌우더니 감옥에 가두려하더라고.","JPN":"まともな状態ではないね。私に会社に忍び込んできたスパイと濡れ衣を着せて、監獄に閉じ込めようとしてたよ。","ENG":"He's definitely not normal. He accused me of being a spy and tried to throw me in jail.","TWN":"根本是非常不正常的情況。 說我是躲在公司的間諜，還冤枉我，又想把我關進監獄。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"그 점은 제가 대신 사과드릴게요!","JPN":"それは僕が代わりに謝罪します！","ENG":"Please let me apologize for that on his behalf!","TWN":"這點我替代表道歉！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"하지만 사실 대표님은 원래 누구보다 밝고 쾌활한 분이었어요.","JPN":"でも本当の社長は元々誰よりも明るくて陽気な方だったんです。","ENG":"You may not believe this, but the Boss used to be more cheery than anyone.","TWN":"但是事實上，代表大人本來是個比任何人都開朗又愉快的人。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"하지만 매출이 급격히 줄어들고 수익이 마이너스가 된 뒤로, 자금난으로 인한 스트레스와 잦은 야근의 피로가 겹치면서 점점 성격이 변하기 시작하셨죠.","JPN":"でも売上が激減して収益がマイナスになってから、資金難によるストレスや残業の疲れが重なり、次第に性格が変わっていったんです。","ENG":"But ever since our sales plummeted and put us in the red, all that stress, compounded with fatigue from working overtime, turned him all strange.","TWN":"但是，在銷售額急劇減少、收益出現負數之後，由於資金困難帶來的壓力和頻繁加班的疲勞，性格開始逐漸發生了扭曲。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"회사가...... 적자라고?","JPN":"会社が……赤字なの？","ENG":"The company... is losing money?","TWN":" 公司…虧損？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"선더볼트단의 규모만 봐도 그렇게 인기가 없는 게임은 아니어 보이던데.","JPN":"サンダーボルト団の規模を見る限り、そんなに人気のないゲームには見えなかったのに。","ENG":"But with all those Thunderbolt fans, I thought the game was pretty popular.","TWN":"單從雷電團的規模來看，也不是那麼不受歡迎的遊戲。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"맞아요! 저희 게임은 수년에 걸쳐 매출 1위를 단 한 번도 놓쳐본 적이 없었어요.","JPN":"そうなんです！　うちのゲームは数年間ずっと売上1位を逃したことはないんですよ。","ENG":"You're right! For years, our game has always been at the top of the charts!","TWN":"沒錯！我們的遊戲在這幾年一次也沒有錯過銷售額第一的位置。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"......적어도 지난 달까지는 그랬죠.","JPN":"……少なくとも先月までは。","ENG":"...Until last month, anyway.","TWN":" ……至少是在前一個月也是如此。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"5주년을 기념해서 대표님 주도로 페이백 5000% 이벤트를 감행하는 바람에 수익구조가 완전히 무너져버렸거든요.","JPN":"5周年を記念して社長主導でキャッシュバック5000％イベントを敢行したせいで、収益構造が完全に崩れてしまったんです。","ENG":"The Boss broke our revenue model by offering a 5,000% payback event in celebration of our five-year anniversary.","TWN":"爲了紀念5週年，在代表的主導下，強行舉辦了5000% 回饋的活動，而導致收益結構完全崩潰。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"그, 그래도 그때까지 벌어들인 돈은 있을 거 아냐? 그 돈은 전부 어디에 있는데?","JPN":"で、でもそれまで稼いだ分の資金は？　そのお金はどこに使ったの？","ENG":"B-but you guys must have saved up some money. Where's all that?","TWN":"可、可是應該會有截至目前爲止賺的錢吧？ 那筆錢到哪去了？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SORIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"얼마 전, 직원복지를 위해 사무실 안에 야생곰이 뛰어놀 수 있는 삼림환경을 조성하는 데 썼지.","JPN":"この前、福利厚生の一環でオフィスの中に野生のクマが走り回れるような森林環境を作る時に使ってしまった。","ENG":"The company recently spent a large sum of money on employee benefits, creating an artificial forest for wild bears in the office.","TWN":"不久前，爲了員工的福利，辦公室裡爲野生熊建造了可以玩耍的森林環境而花光了。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L28_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"올 하반기에 개봉 예정인 애니메이션 [간다 나의 선더볼트!] 시즌8 제작에도 투자가 많이 들어 갔어요.","JPN":"今年の下半期に公開する予定のアニメーション[行くぞ、最強サンダーボルト！] シーズン8の製作にもかなり投資していたんです。","ENG":"And lots of investment was made in the upcoming Season 8 of the animated series, Here Comes My Thunderbolt!","TWN":"預計今年下半年上映的動畫片《去吧，我的雷電》 第8季的製作也投入了不少投資費用。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L29_1","type":"dialog","speaker":"SORIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"[간다 나의 선더볼트!]는 본관 또한 넷플렉스에서 꼬박꼬박 시청하고 있는 인기 애니메이션이다.","JPN":"[行くぞ、最強サンダーボルト！]は本官も毎回欠かさず視聴している人気アニメである。","ENG":"I've personally never missed an episode of that. It's one of the most popular shows streaming on Webflix.","TWN":"《去吧，我的雷電！》是本官在Netflxx持續在追的人氣動畫"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SORIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"본방 때마다 이벤트를 열어 선더볼트 굿즈도 무료나눔을 하고 있으니 자네도 신청하도록.","JPN":"放送のたびにイベントを行い、サンダーボルトグッズを無料で配っているので、君も申し込むように。","ENG":"They hold a raffle for free merchandise when they air each episode. You should try your luck at that too.","TWN":"每次播出時都會舉行活動，免費贈送雷電的周邊商品，你也可以申請一下。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"음, 그리고 또......","JPN":"えっと、それに……","ENG":"And also...","TWN":"嗯，還有……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"......저기, 회사 사정이 나빠졌는데도 계속 그런 식으로 돈을 쓰면 적자가 날 수밖에 없지 않아?","JPN":"……あのさ、会社の経営事情が悪くなったのに、そんなところにお金を使ってたら赤字になるのは当たり前なんじゃないの？","ENG":"No wonder you guys are in the red! You can't keep spending like that when your finances are worsening!","TWN":"……那個，既然公司情況變差了，還繼續那樣花錢，不就只會一直虧損嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"대표님은 언제나 최고의 게임회사다운 경영을 하고 싶어하셨어요.","JPN":"社長は常に最高のゲーム会社らしい経営を夢見ていました。","ENG":"The Boss always wanted to make this the greatest game company ever.","TWN":"代表一直希望經營一家最友善的遊戲公司。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"아무리 회사 형편이 나빠져도 직원들과 유저에게 했던 약속을 져버릴 순 없다고 하셨죠.","JPN":"いくら会社の状況が悪くなったとしても、社員とユーザーにした約束を破ることはできないと言っていました。","ENG":"No matter how tough things got, he said he couldn't break his promise to the employees and the players.","TWN":"他說，即使公司條件再差，也不能放棄員工和玩家間的約定。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"그랬던 대표님이...... 저렇게 완전히 다른 사람처럼 변하시다니.","JPN":"そんな社長が……あんな別人みたいになっちゃうなんて。","ENG":"That's the sort of boss he used to be... but now it's like he's someone else entirely.","TWN":"這樣的代表… 就那樣完全變成另外一個人了。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"......그래도 회사가 파산 직전까지 돈을 쓰는 건 좀 그렇지 않아?","JPN":"……だとしても、会社が破産寸前になるまでお金を使うのはちょっと違うんじゃない？","ENG":"...Still, don't you think it's problematic to spend so much that you're driven to bankruptcy?","TWN":"…………但是公司到破產爲止花錢是不是有點過於誇張？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"하지만 고작 한 달 만에 파산 위기에 몰릴 정도로 예산이 부족하진 않았어요!","JPN":"でも、たった一ヶ月で破産の危機に追い込まれるほど予算が足りないわけではなかったんですよ！","ENG":"But we were never so strapped for cash that we'd become nearly bankrupt... in just a month!","TWN":"但是僅僅一個月就面臨破產危機，本來預算並不缺！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"마치 구멍이라도 난 것처럼 한순간에 예산이 사라져버렸다고요!","JPN":"まるでどこかに穴が空いたみたいに、あっという間に予算が消えてしまったんです。","ENG":"The money just disappeared, as if someone poked a hole in our account!","TWN":"就像突然出現了一個破口一樣，預算在一瞬間消失了！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"하아......","JPN":"はあ……","ENG":"*Sigh*","TWN":"哈啊……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"황금 같은 주말에 내가 왜 이런 일을 겪고 있는 건지, 아직도 실감이 안 나네.","JPN":"貴重な週末になんでこんな目に遭っているのか、まだ実感がわかないや。","ENG":"I still can't believe I'm going through this crap on my precious weekend.","TWN":"在黃金週末時光為什麼讓我經歷這些事，到現在還不敢相信。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"도와준 건 고맙지만 난 이 회사의 문제를 해결해주러 온 사람이 아니야.","JPN":"助けてくれたのはありがたいけど、私はこの会社の問題を解決するために来たわけじゃない。","ENG":"I appreciate the help, but I'm not here to solve your company's problems.","TWN":"雖然很謝謝你的幫助，但我不是來解決這家公司問題的人。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"난 집으로 돌아가고 싶을 뿐이라고.","JPN":"ただ、家に帰りたいだけなの。","ENG":"I just want to go home, that's all.","TWN":"我只是想回家而已。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"앗, 그랬었죠. 죄송해요.","JPN":"ああ、そうでしたよね。すみません……","ENG":"Oh, right. Sorry.","TWN":"咦，對吼，真抱歉。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"이런 문젯거리를 얘기로 나눌 사람이 별로 없다 보니 제가 너무 흥분했네요.","JPN":"この問題を話し合える人がほとんどいなくて、つい興奮して色々と話してしまいました。","ENG":"I just got carried away since there aren't that many folks I can share this with.","TWN":"因爲很少有人能跟我把這些問題提出來做討論，所以我不自覺就說了太多了。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"저도 언니가 어떻게든 무사히 돌아갈 수 있도록 최대한 도와줄게요.","JPN":"僕もお姉ちゃんが無事に帰れるように、できるだけお手伝いします。","ENG":"In any case, I'll help you as much as I can so you can go back home.","TWN":"我也會盡最大努力幫助姐姐平安回家的。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":" ……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"아무튼 유감이네. 당신들 문제도 잘 해결되길 바라......","JPN":"悪いね。あなたたちの問題もうまく解決できるといい……","ENG":"Well, I'm sorry you guys have to go through all that. Hopefully everything will work out for you—","TWN":"總之我也覺得很遺憾。 希望你們的問題也能得到解決……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"뭐, 뭐야? 역시 들킨 건가?","JPN":"な、なに？　やっぱり居場所がバレた？","ENG":"W-what was that? Did they find us?","TWN":"什、什麼啊？難道是被發現了？"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_MONSTER_GRAVE_MINI_SKILL"},{"id":"L1_1","type":"dialog","speaker":"SORIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"그게 아니다. 저건......!","JPN":"違う。あれは……！","ENG":"No. That is…!","TWN":"好像不是，那是……！"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_NPC_FOOLSDAY_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};